// ── Build DOCX template variables ──
const body = $input.first().json.body;

const lang = body.language || 'en';
const isFr = lang === 'fr';

// Labels (bilingual)
const labels = {
  invoiceTitle:     isFr ? 'FACTURE'              : 'INVOICE',
  billTo:           isFr ? 'Facturé à'             : 'Billed to',
  from:             isFr ? 'Émetteur'              : 'From',
  description:      isFr ? 'Description'           : 'Description',
  amount:           isFr ? 'Montant'               : 'Amount',
  taxableAmount:    isFr ? 'Montant HT'            : 'Taxable amount',
  vatLabel:         isFr ? `TVA (${body.amounts.vatRate}%)` : `VAT (${body.amounts.vatRate}%)`,
  totalLabel:       isFr ? 'Total (TVA incluse)'   : 'Total (VAT incl.)',
  serviceLabel:     isFr ? 'Prestation'            : 'Service',
  typeLabel:        isFr ? 'Type'                  : 'Type',
  boatLabel:        isFr ? 'Bateau'                : 'Boat',
  datesLabel:       isFr ? 'Dates début / fin'     : 'Start / End dates',
  portsLabel:       isFr ? 'Port départ / arrivée' : 'Starting / Landing Port',
  travellersLabel:  isFr ? 'Nb. de voyageurs'      : 'Nb. of travellers',
  priceLabel:       isFr ? 'Montant total client'  : "Client's total amount",
};

// Format amounts
const fmt = (n) => new Intl.NumberFormat('fr-FR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(n);

const desc = body.description;
const boatFull = [desc.boatModel, desc.boatYear ? `(${desc.boatYear})` : null].filter(Boolean).join(' ');
const datesFull = [desc.startDate, desc.endDate].filter(Boolean).join(' → ');
const portsFull = [desc.startingPort, desc.landingPort].filter(Boolean).join(' / ');

return [{
  json: {
    // Pass-through for downstream nodes
    ...body,

    // Template variables for DOCX placeholders
    INVOICE_TITLE:      labels.invoiceTitle,
    INVOICE_NUMBER:     body.invoiceNumber,
    INVOICE_DATE:       body.invoiceDate,
    LANG:               lang,

    // Recipient
    BILL_TO_LABEL:      labels.billTo,
    RECIPIENT_NAME:     body.recipient.name,
    RECIPIENT_ADDRESS:  body.recipient.address,
    RECIPIENT_COUNTRY:  body.recipient.country,
    RECIPIENT_VAT:      body.recipient.vatNumber ? `VAT: ${body.recipient.vatNumber}` : '',

    // Issuer
    FROM_LABEL:         labels.from,
    ISSUER_NAME:        body.issuer.name,
    ISSUER_ADDRESS:     body.issuer.address,
    ISSUER_PHONE:       body.issuer.phone,
    ISSUER_EMAIL:       body.issuer.email,

    // Description
    DESC_LABEL:         labels.description,
    AMOUNT_LABEL:       labels.amount,
    SERVICE_LABEL:      labels.serviceLabel,
    SERVICE_VALUE:      desc.serviceName,
    TYPE_LABEL:         labels.typeLabel,
    TYPE_VALUE:         desc.serviceType || '',
    BOAT_LABEL:         labels.boatLabel,
    BOAT_VALUE:         boatFull,
    DATES_LABEL:        labels.datesLabel,
    DATES_VALUE:        datesFull,
    PORTS_LABEL:        labels.portsLabel,
    PORTS_VALUE:        portsFull,
    TRAVELLERS_LABEL:   labels.travellersLabel,
    TRAVELLERS_VALUE:   desc.nbTravellers?.toString() || '',
    PRICE_LABEL:        labels.priceLabel,
    PRICE_VALUE:        desc.clientTotalPrice || '',

    // Amounts
    TAXABLE_LABEL:      labels.taxableAmount,
    TAXABLE_VALUE:      `€${fmt(body.amounts.taxable)}`,
    VAT_LABEL:          labels.vatLabel,
    VAT_VALUE:          `€${fmt(body.amounts.vatAmount)}`,
    TOTAL_LABEL:        labels.totalLabel,
    TOTAL_VALUE:        `€${fmt(body.amounts.total)}`,
    VAT_NOTE:           body.amounts.vatNote || '',

    // Footer
    FOOTER_TEXT:        body.footerText,

    // PDF filename
    PDF_FILENAME:       `${body.invoiceNumber}_${body.recipient.name.replace(/[^a-z0-9]/gi, '_')}.pdf`,
  }
}];

// ── Fill DOCX template placeholders ──
// Uses docxtemplater to replace {{PLACEHOLDER}} in the DOCX
// This node requires the 'docxtemplater' and 'pizzip' npm packages
// installed in the n8n custom nodes directory.
//
// Alternative: use the HTTP Request node to call a serverless
// function (Vercel Edge / Cloudflare Worker) that does the DOCX fill.
//
// For simplicity in n8n, the recommended approach is to use
// a dedicated microservice or call a Vercel API route:
// POST /api/generate-pdf with the full payload.
//
// The Vercel API route at /api/generate-pdf:
//   1. Downloads the template
//   2. Fills it with docxtemplater
//   3. Converts to PDF with LibreOffice (via a conversion API)
//   4. Returns the PDF as a buffer
//
// Returning pass-through here; actual PDF generation
// is handled by the HTTP Request node below.
return $input.all();
